<svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="28" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">IBIT's Assets Fell, But Fee Revenue Held</text>
  <text x="20" y="47" fill="#a1a1aa" font-size="13" font-family="sans-serif">Based on Q2 2026 results</text>
  <line x1="40" y1="340" x2="330" y2="340" stroke="rgba(255,255,255,.15)" stroke-width="1"/>
